// ============================================
// CATÁLOGO CENTRAL — única fonte de verdade
// Edite SOMENTE aqui ao adicionar novas APIs
// ============================================

const catalogo = [
  {
    id: "ServicoDeColaborador_v2",
    nome: "Serviço de Colaborador (versão 2)",
    descricao: "Gestão de dados do colaborador.",
    url: "https://prd-api1.lg.com.br/v2/ServicoDeColaborador?wsdl"
  },
  {
    id: "ServicoDeColaborador_v1",
    nome: "Serviço de Colaborador (versão 1)",
    descricao: "Versão anterior do serviço de dados do colaborador.",
    url: "https://prd-api1.lg.com.br/v1/ServicoDeColaborador?wsdl"
  },
  {
    id: "ServicoDeContratoDeTrabalho_v2",
    nome: "Serviço de Contrato de Trabalho (versão 2)",
    descricao: "Gestão de contratos de trabalho.",
    url: "https://prd-api1.lg.com.br/v2/ServicoDeContratoDeTrabalho?wsdl"
  },
  {
    id: "ServicoDeContratoDeTrabalho_v1",
    nome: "Serviço de Contrato de Trabalho (versão 1)",
    descricao: "Versão anterior do serviço de contratos.",
    url: "https://prd-api1.lg.com.br/v1/ServicoDeContratoDeTrabalho?wsdl"
  },
  {
    id: "ServicoDeReintegracao_v1",
    nome: "Serviço de Reintegração (versão 1)",
    descricao: "Processos de reintegração de colaborador.",
    url: "https://prd-api1.lg.com.br/v1/ServicoDeReintegracao?wsdl"
  }
];

// Texto para o System Message
const catalogoTexto = catalogo
  .map(api => `- ${api.id} — ${api.nome}. ${api.descricao}`)
  .join('\n');

// Mapa id→url para o Resolver URL
const catalogoMapa = {};
for (const api of catalogo) {
  catalogoMapa[api.id] = api.url;
}

const input = $input.first().json;

return [{
  json: {
    question: input.question,
    session_id: input.session_id,
    catalogo_texto: catalogoTexto,
    catalogo_mapa: JSON.stringify(catalogoMapa)
  }
}];
